async (page) => {
  // Collect logs by periodically clicking tree tiles nearby
  // Using multiple trees for efficiency
  const trees = [{x:214,y:118},{x:219,y:112},{x:225,y:117}];
  let treeIdx = 0;

  let initial = await page.evaluate(() => window.__latestGameState.inventory.filter(i => i.name === 'Logs').length);
  console.log('Starting logs: ' + initial);

  for (let round = 0; round < 15; round++) {
    const t = trees[treeIdx % trees.length];
    await page.evaluate(({x, y}) => window.__clickTile(x, y), t);
    await page.waitForTimeout(10000);
    treeIdx++;

    const current = await page.evaluate(() => window.__latestGameState.inventory.filter(i => i.name === 'Logs').length);
    if (current >= 12) {
      console.log('Enough logs: ' + current);
      break;
    }
  }

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({logs: s.inventory.filter(i => i.name === 'Logs').length, pos: s.player_position});
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return state;
}

