async (page) => {
  // Continue fighting nearby mobs - rapid kill loop
  for (let round = 0; round < 4; round++) {
    // Get fresh entities
    const mob = await page.evaluate(() => {
      const s = window.__latestGameState;
      const m = s.nearby_entities.find(e => e.type === 3 && e.distance <= 8 && e.on_screen);
      return m ? {idx: s.nearby_entities.indexOf(m), name: m.name, hp: m.hp, dist: m.distance} : null;
    });

    if (!mob) break;

    const label = 'E' + mob.idx;
    await page.evaluate((lbl) => window.__clickEntity(lbl), label);
    await page.waitForTimeout(6000);

    const hp = await page.evaluate(() => window.__latestGameState.player_stats.hp);
    if (hp < 124) break; // Below 40%, stop fighting
  }

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({hp: s.player_stats.hp, pos: s.player_position, nearby_mobs: s.nearby_entities.filter(e=>e.type===3&&e.distance<10).length, skills: s.skills});
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return state;
}

